.darma-loader-darma-custom-097 {
  width: 40px;
  height: 60px;
  position: relative;
}
.darma-loader-darma-custom-097::before,
.darma-loader-darma-custom-097::after {
  content: "";
  position: absolute;
  inset: 0;
  background: #514b82;
  clip-path: polygon(0 0,100% 0, 100% 67%,50% 67%,50% 34%,0 34%);
  animation: darma-loader-darma-custom-097-sp7 2s infinite;
}
.darma-loader-darma-custom-097::after {
  --s:-1,-1;
}
@keyframes darma-loader-darma-custom-097-sp7 {
    0%,
    10%  {transform:scale(var(--s,1)) translate(0,0)        rotate(0deg)}
    33%  {transform:scale(var(--s,1)) translate(0,-20px)    rotate(0deg)}
    66%  {transform:scale(var(--s,1)) translate(10px,-20px) rotate(-90deg)}
    90%,
    100% {transform:scale(var(--s,1)) translate(10px,-10px) rotate(-90deg)}
}

